import json
# Access previous tool results
reviews = var_call_b8HfUBszdG14POQpLGKUHLSN
business_docs = var_call_voUDIPSKfaICkEx5qRiIFVJF

# Build set of business_ids that had reviews in 2018
reviewed_business_ids = set()
for r in reviews:
    br = r.get('business_ref')
    if br and isinstance(br, str) and br.startswith('businessref_'):
        reviewed_business_ids.add(br.replace('businessref_', 'businessid_'))

# Filter business docs to only those corresponding to reviewed businesses
filtered = [b for b in business_docs if b.get('business_id') in reviewed_business_ids]

def offers_parking(attrs):
    if not attrs or not isinstance(attrs, dict):
        return False
    # Check BikeParking
    bike = attrs.get('BikeParking')
    if bike is not None and str(bike).lower() == 'true':
        return True
    # Check BusinessParking
    bp = attrs.get('BusinessParking') or attrs.get('BusinessParking')
    if bp is not None:
        s = str(bp).lower()
        if 'true' in s:
            return True
    # Sometimes key might be 'BusinessParking' differently cased - check all keys
    for k, v in attrs.items():
        if k and k.lower() == 'bikeparking' and str(v).lower() == 'true':
            return True
        if k and k.lower() == 'businessparking' and v is not None:
            if 'true' in str(v).lower():
                return True
    return False

count = 0
businesses_with_parking = []
for b in filtered:
    attrs = b.get('attributes')
    if offers_parking(attrs):
        count += 1
        businesses_with_parking.append(b.get('business_id'))

# For transparency in result, include the count and the list of business_ids
result = {"count": count, "business_ids": businesses_with_parking}

print("__RESULT__:")
print(json.dumps(result))

